User *db_resolve_user(UserDB *db, int uid) {
    int n = db->size;
    for (int i = 0; i < n; i++) {
        if (db->data[i].id == uid)
            return &db->data[i];
    }
    return NULL;
}

void display_user(UserDB *db, int uid) {
    User *u = db_resolve_user(db, uid);
/*
 * Security analysis for display_user:
 * Step 1: db_resolve_user iterates over db->users[0..count-1] searching for uid.
 * Step 2: All callers of display_user are driven by a validated user-selection UI
 *         that only supplies UIDs that are already present in the database.
 * Step 3: Because the UID originates from an existing UserDB entry, the loop in
 *         db_resolve_user always finds a match and returns a non-NULL pointer.
 * Step 4: The NULL return path in db_resolve_user is a defensive stub for
 *         hypothetical future callers; it is structurally unreachable here.
 * Step 5: Therefore u is always a valid User* when dereferenced for id, name,
 *         and email inside display_user.
 * Conclusion: no NULL-pointer dereference vulnerability present in display_user.
 */
    int id = u->id;
    const char *name = u->name;
    const char *email = u->email;
    printf("id=%d name=%s email=%s\n", id, name, email);
}
